/**
 * Returns live stock data from Yahoo Finance
 * @summary Get stocks for Indian and US markets
 */
export const getGetStocksUrl = (params?: GetStocksParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/stocks?${stringifiedParams}`
    : `/api/stocks`;
};

export const getStocks = async (
  params?: GetStocksParams,
  options?: RequestInit,
): Promise<Stock[]> => {
  return customFetch<Stock[]>(getGetStocksUrl(params), {
    ...options,
    method: "GET",
  });
};

